// HasPurchaseReceipt applies the HasEdge predicate on the "purchase_receipt" edge.
func HasPurchaseReceipt() predicate.PurchaseReturn {
	return predicate.PurchaseReturn(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, PurchaseReceiptTable, PurchaseReceiptColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasPurchaseReceiptWith applies the HasEdge predicate on the "purchase_receipt" edge with a given conditions (other predicates).
func HasPurchaseReceiptWith(preds ...predicate.PurchaseReceipt) predicate.PurchaseReturn {
	return predicate.PurchaseReturn(func(s *sql.Selector) {
		step := newPurchaseReceiptStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

