// And groups predicates with the AND operator between them.
func And(predicates ...predicate.PurchaseReturn) predicate.PurchaseReturn {
	return predicate.PurchaseReturn(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.PurchaseReturn) predicate.PurchaseReturn {
	return predicate.PurchaseReturn(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.PurchaseReturn) predicate.PurchaseReturn {
	return predicate.PurchaseReturn(sql.NotPredicates(p))
}
